/*  
Эта реализация учебная. Она использует new T[capacity_], поэтому тип T должен иметь конструктор по умолчанию. 
Настоящий std::vector устроен сложнее: он выделяет сырую память и отдельно конструирует только реально добавленные элементы.
*/

#pragma once

#include <cstddef>
#include <stdexcept>
#include <utility>

template <typename T>
class DynamicArray {
public:
    DynamicArray() : capacity_(8), size_(0), data_(new T[capacity_]) {}

    explicit DynamicArray(std::size_t aCapacity) : capacity_(aCapacity), size_(0), data_(new T[capacity_]) {}

    DynamicArray(const DynamicArray& other) : capacity_(other.capacity_), size_(other.size_), data_(new T[other.capacity_]) {
        for (std::size_t i = 0; i < size_; ++i) {
            data_[i] = other.data_[i];
        }
    }

    DynamicArray(DynamicArray&& other) noexcept : capacity_(other.capacity_), size_(other.size_), data_(other.data_) {
        other.data_ = nullptr;
        other.capacity_ = 0;
        other.size_ = 0;
    }

    ~DynamicArray() {
        delete[] data_;
    }

    std::size_t size() const { return size_; }

    std::size_t capacity() const { return capacity_; }

    T* data() { return data_; }

    const T* data() const { return data_; }

    T* begin() { return data_; }

    const T* begin() const { return data_; }

    const T* cbegin() const { return data_; }

    T* end() { return data_ + size_; }

    const T* end() const { return data_ + size_; }

    const T* cend() const { return data_ + size_; }

    bool empty() const { return size_ == 0; }

    void reserve(std::size_t newCapacity) {
        if (newCapacity <= capacity_) return;

        T* newData = new T[newCapacity];

        for (std::size_t i = 0; i < size_; ++i) {
            newData[i] = std::move(data_[i]);
        }

        delete[] data_;

        data_ = newData;
        capacity_ = newCapacity;
    }

    void clear() { size_ = 0; }

    T& at(std::size_t index) {
        if (index >= size_) {
            throw std::out_of_range("Index out of range");
        }
        return data_[index];
    }

    const T& at(std::size_t index) const {
        if (index >= size_) {
            throw std::out_of_range("Index out of range");
        }
        return data_[index];
    }

    void pushBack(const T& element) {
        if (size_ >= capacity_) {
            reallocate();
        }
        data_[size_++] = element;
    }

    void pushBack(T&& element) {
        if (size_ >= capacity_) {
            reallocate();
        }
        data_[size_++] = std::move(element);
    }

    void popBack() {
        if (empty()) {
            throw std::out_of_range("DynamicArray is empty");
        }
        --size_;
    }

    T& front() {
        if (empty()) {
            throw std::out_of_range("DynamicArray is empty");
        }
        return data_[0];
    }

    const T& front() const {
        if (empty()) {
            throw std::out_of_range("DynamicArray is empty");
        }
        return data_[0];
    }

    T& back() {
        if (empty()) {
            throw std::out_of_range("DynamicArray is empty");
        }
        return data_[size_ - 1];
    }

    const T& back() const {
        if (empty()) {
            throw std::out_of_range("DynamicArray is empty");
        }
        return data_[size_ - 1];
    }

    void erase(std::size_t index) {
        if (index >= size_) {
            throw std::out_of_range("Index out of range");
        }
        for (std::size_t i = index; i + 1 < size_; ++i) {
            data_[i] = std::move(data_[i + 1]);
        }
        --size_;
    }

    T& operator[](std::size_t index) { return data_[index]; }

    const T& operator[](std::size_t index) const { return data_[index]; }

    DynamicArray& operator=(const DynamicArray& other) {
        if (this == &other) return *this;

        T* newData = new T[other.capacity_];

        for (std::size_t i = 0; i < other.size_; ++i) {
            newData[i] = other.data_[i];
        }

        delete[] data_;

        data_ = newData;
        capacity_ = other.capacity_;
        size_ = other.size_;

        return *this;
    }

    DynamicArray& operator=(DynamicArray&& other) noexcept {
        if (this == &other) return *this;

        delete[] data_;

        capacity_ = other.capacity_;
        size_ = other.size_;
        data_ = other.data_;

        other.data_ = nullptr;
        other.capacity_ = 0;
        other.size_ = 0;

        return *this;
    }

    std::size_t find(const T& element) const {
        for (std::size_t i = 0; i < size_; ++i) {
            if (data_[i] == element) return i;
        }

        throw std::runtime_error("Element not found");
    }

    bool contains(const T& element) const {
        for (std::size_t i = 0; i < size_; ++i) {
            if (data_[i] == element) return true;
        }
        return false;
    }

    bool operator==(const DynamicArray& other) const {
        if (size_ != other.size_) return false;

        for (std::size_t i = 0; i < size_; ++i) {
            if (data_[i] != other.data_[i]) return false;
        }

        return true;
    }

private:
    std::size_t capacity_;
    std::size_t size_;
    T* data_;

    void reallocate() {
        std::size_t newCapacity = capacity_ == 0 ? 1 : capacity_ * 2;
        reserve(newCapacity);
    }
};
